// WebGPU compat test #8 — aether's RMSNorm WGSL kernel under monster.
//
// WGSL_RMSNORM copied VERBATIM from
//   open-source/aether/dist-browser/sovereign-shaders.js
// out[i] = x[i] * (1/sqrt(mean(x^2)+eps)) * weight[i], one workgroup (256
// threads) with a shared-memory tree reduction over n. This is the per-token
// (non-batched) RMSNorm the decode path uses. Golden-diffed monster vs the Deno
// real-navigator.gpu oracle via run.mjs canonical-JSON compare.
//
// Inline pure-JS IEEE encoders (monster has no DataView and no cross-file ESM
// imports — every helper must live in this file). f32 inputs are exact small
// values; output quantized to 1e-4 to absorb sub-ULP backend divergence in the
// inverseSqrt + reduction.

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0; x = Math.abs(x);
  let e = Math.floor(Math.log2(x)); let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; } if (m >= 2) { m /= 2; e += 1; }
  const bits = ((sign << 31) | ((e + 127) << 23) | Math.round((m - 1) * Math.pow(2, 23))) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1; const exp = (bits >>> 23) & 0xff; const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}
function u32bytes(v) { return [v & 0xff, (v >>> 8) & 0xff, (v >>> 16) & 0xff, (v >>> 24) & 0xff]; }
function q4(v) { const s = v < 0 ? -1 : 1; return s * Math.round(Math.abs(v) * 1e4) / 1e4; }

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

// n = 320 (> 256 so the per-thread strided loop runs more than one iteration,
// exercising the reduction). eps = 1e-6. x[i] and weight[i] are small exact f32.
const N = 320;
const EPS = 0.000001;
function xval(i) { return ((i % 7) - 3) * 0.25; }      // -0.75..0.75
function wval(i) { return 1 + ((i % 5) - 2) * 0.0625; } // 0.875..1.125, half-exact

let xBytes = [];
for (let i = 0; i < N; i++) xBytes = xBytes.concat(f32bytes(xval(i)));
let wBytes = [];
for (let i = 0; i < N; i++) wBytes = wBytes.concat(f32bytes(wval(i)));
let dimBytes = u32bytes(N).concat(f32bytes(EPS)); // NormDims { n: u32, eps: f32 }

const X_BYTES = N * 4, W_BYTES = N * 4, OUT_BYTES = N * 4, DIM_BYTES = 8;

const xBuf = device.createBuffer({ size: X_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(xBuf, 0, new Uint8Array(xBytes));
const wBuf = device.createBuffer({ size: W_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(wBuf, 0, new Uint8Array(wBytes));
const oBuf = device.createBuffer({ size: OUT_BYTES, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC });
const dBuf = device.createBuffer({ size: DIM_BYTES, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(dBuf, 0, new Uint8Array(dimBytes));

const shader = device.createShaderModule({
  code: `
struct NormDims { n: u32, eps: f32 };
@group(0) @binding(0) var<storage, read> x: array<f32>;
@group(0) @binding(1) var<storage, read> weight: array<f32>;
@group(0) @binding(2) var<storage, read_write> out: array<f32>;
@group(0) @binding(3) var<uniform> d: NormDims;

var<workgroup> partial: array<f32, 256>;

@compute @workgroup_size(256, 1, 1)
fn main(@builtin(local_invocation_id) lid: vec3<u32>) {
  let tid = lid.x;
  var s: f32 = 0.0;
  var i: u32 = tid;
  loop {
    if (i >= d.n) { break; }
    let v = x[i];
    s = s + v * v;
    i = i + 256u;
  }
  partial[tid] = s;
  workgroupBarrier();
  var stride: u32 = 128u;
  loop {
    if (stride == 0u) { break; }
    if (tid < stride) { partial[tid] = partial[tid] + partial[tid + stride]; }
    workgroupBarrier();
    stride = stride >> 1u;
  }
  let inv = inverseSqrt(partial[0] / f32(d.n) + d.eps);
  var j: u32 = tid;
  loop {
    if (j >= d.n) { break; }
    out[j] = x[j] * inv * weight[j];
    j = j + 256u;
  }
}
`,
});
const pipeline = device.createComputePipeline({ layout: 'auto', compute: { module: shader, entryPoint: 'main' } });
const bindGroup = device.createBindGroup({
  layout: pipeline.getBindGroupLayout(0),
  entries: [
    { binding: 0, resource: { buffer: xBuf } },
    { binding: 1, resource: { buffer: wBuf } },
    { binding: 2, resource: { buffer: oBuf } },
    { binding: 3, resource: { buffer: dBuf } },
  ],
});

const enc = device.createCommandEncoder();
const pass = enc.beginComputePass();
pass.setPipeline(pipeline);
pass.setBindGroup(0, bindGroup);
pass.dispatchWorkgroups(1, 1, 1);
pass.end();
const readBuf = device.createBuffer({ size: OUT_BYTES, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
enc.copyBufferToBuffer(oBuf, 0, readBuf, 0, OUT_BYTES);
device.queue.submit([enc.finish()]);

await readBuf.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(readBuf.getMappedRange());
let gpu = [];
for (let i = 0; i < N; i++) { const o = i * 4; gpu = gpu.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]); }
readBuf.unmap();

// Independent CPU reference.
let ss = 0;
for (let i = 0; i < N; i++) ss += xval(i) * xval(i);
const inv = 1 / Math.sqrt(ss / N + EPS);
let cpu = [];
for (let i = 0; i < N; i++) cpu = cpu.concat([xval(i) * inv * wval(i)]);

// Report a few sampled elements + a checksum (sum) so the JSON stays compact but
// any per-element divergence still moves the sum.
function sum(a) { let s = 0; for (let i = 0; i < a.length; i++) s += a[i]; return s; }
out.gpuSample = [q4(gpu[0]), q4(gpu[1]), q4(gpu[159]), q4(gpu[319])];
out.cpuSample = [q4(cpu[0]), q4(cpu[1]), q4(cpu[159]), q4(cpu[319])];
out.gpuSum = q4(sum(gpu));
out.cpuSum = q4(sum(cpu));
console.error('RAW gpu[0..3]=' + JSON.stringify(gpu.slice(0, 4)) + ' inv=' + inv);
console.log('__RESULT__ ' + JSON.stringify(out));
